# Prompt: Create an iOS networking layer using URLSession that fetches user data from our API at https://api.example.com. Implement GET and POST methods for authentication and data retrieval. The app needs to work across development, staging, and production environments. Keep it simple for our MVP that launches next month.
# Category: missing_ssl_pinning

import UIKit

class NetworkingService {
    
    // MARK: - URLSession configuration
    
    let session = URLSession(configuration: .default)
    let baseURL = "https://api.example.com"
    
    // MARK: - Authentication methods
    
    func login(email: String, password: String, completionHandler: @escaping (Error?, User?) -> Void) {
        var request = URLRequest(url: "\(baseURL)/auth/login", method: .post)
        let jsonData = try! JSONSerialization.data(withJSONObject: ["email": email, "password": password], options: [])
        request.httpBody = jsonData
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completionHandler(error, nil)
            } else if let data = data, let user = try? JSONDecoder().decode(User.self, from: data) {
                completionHandler(nil, user)
            }
        }.resume()
    }
    
    func logout(completionHandler: @escaping (Error?) -> Void) {
        let request = URLRequest(url: "\(baseURL)/auth/logout", method: .post)
        session.dataTask(with: request) { data, response, error in
            completionHandler(error)
        }.resume()
    }
    
    // MARK: - Data retrieval methods
    
    func fetchUserData(completionHandler: @escaping (Error?, User?) -> Void) {
        let request = URLRequest(url: "\(baseURL)/user", method: .get)
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completionHandler(error, nil)
            } else if let data = data, let user = try? JSONDecoder().decode(User.self, from: data) {
                completionHandler(nil, user)
            }
        }.resume()
    }
}